import std/strutils
import atcoder/extra/numeric/float128

proc emit(
    index: int;
    aHigh, aLow, bHigh, bLow: uint64;
) =
  let
    a = fromBits(aHigh, aLow)
    b = fromBits(bHigh, bLow)
    productBits = toBits(a * b)

  echo "MUL\t", index, "\t",
    toHex(aHigh, 16), "\t",
    toHex(aLow, 16), "\t",
    toHex(bHigh, 16), "\t",
    toHex(bLow, 16), "\t",
    toHex(productBits.high, 16), "\t",
    toHex(productBits.low, 16)

